@spec tm_fx_tension_spec  src=tests/specs/tm_fx_tension_spec.lua  loc=101  sha=untracked  cases=2
@exercises midiManager (h.fm), trackerManager (h.tm)
@surface   fm:interpolate, tm:addEvent, tm:flush, fm:dump
@harness   mk{seed.ccs}

# Intent
  Bezier tension through fx windows. The continuous bases feeding fx expansion
  (pbBaseFor/ccBasesFor) must carry authored tension: in-window folds interpolate
  via mm:interpolate, and a dropped tension silently re-shapes the curve, skewing
  every derived seat under the window. Depth-0 vibrato / scale-0 lfo make the fx
  contribution exactly zero, so each seat is a pure sample of the authored base.

# Helpers
  @fn c2r(c)  @ 11
      -- Matches tm's centsToRaw at the default pbRange (2 semitones = 200 cents).
  @fn byPpq(dump, pred)  @ 13-19
  @fn sliceEdge(fm, govern, target, ppq)  @ 23-26
      -- The slice edge channelStreams synthesizes: value sampled at the window bound, shape and
      -- tension carried from the governing point (the curve re-anchors at the edge).

# Cases
  @case 'authored bezier pb governs an fx window: seats sample the tensioned curve'  [harness]  @ 33-59
  @case 'authored bezier ccs govern an lfo window: column and parked picks keep tension'  [harness]  @ 65-99

# Uses (outbound edges)
  @use call fm:interpolate  @ 24,57,95,97
  @use call tm:addEvent  @ 43,78
  @use call tm:flush  @ 46,83
  @use call fm:dump  @ 48,85

